  1	import * as React from 'react';
  2	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  3	import { screen, render } from '@testing-library/react';
  4	import { userEvent } from '@testing-library/user-event';
  5	import { ActionsColumn, IAction, Td } from '@patternfly/react-table';
  6	import { getName, getNamespace } from '../selectors';
  7	import { RowComponentType } from './composable-table';
  8	import { SelectableTable } from './selectable-table';
  9	
 10	const getRow = (): K8sResourceCommon[] => [
 11	  {
 12	    metadata: {
 13	      uid: '1',
 14	      name: 'name1',
 15	      namespace: 'namespace1',
 16	    },
 17	    kind: 'kind1',
 18	  },
 19	  {
 20	    metadata: {
 21	      uid: '2',
 22	      deletionTimestamp: '2023-06-14T07:37:28Z',
 23	      name: 'name2',
 24	      namespace: 'namespace2',
 25	    },
 26	    kind: 'kind2',
 27	  },
 28	  {
 29	    metadata: {
 30	      uid: '3',
 31	      name: 'name3',
 32	      namespace: 'namespace3',
 33	    },
 34	    kind: 'kind3',
 35	  },
 36	];
 37	
 38	const getColumns = () => [
 39	  { columnName: 'name' },
 40	  { columnName: 'namespace' },
 41	  { columnName: 'kind' },
 42	  { columnName: '' },
 43	];
 44	
 45	const RowActions = (): IAction[] => [
 46	  {
 47	    title: 'test action',
 48	    onClick: jest.fn(),
 49	  },
 50	];
 51	
 52	const MockRowComponent: React.FC<RowComponentType<K8sResourceCommon>> = (
 53	  props
 54	) => {
 55	  const { row } = props;
 56	
 57	  return (
 58	    <>
 59	      <Td> {getName(row)} </Td>
 60	      <Td> {getNamespace(row)} </Td>
 61	      <Td> {row?.kind} </Td>
 62	      <Td isActionCell>
 63	        <ActionsColumn items={RowActions()} />
 64	      </Td>
 65	    </>
 66	  );
 67	};
 68	
 69	describe('ApplicationSet manage data policy modal', () => {
 70	  test('selectable table test', async () => {
 71	    const user = userEvent.setup();
 72	    let selectedRows: K8sResourceCommon[] = [];
 73	    const mockFuncton = jest.fn((selectedRowList: K8sResourceCommon[]) => {
 74	      selectedRows = selectedRowList;
 75	    });
 76	    render(
 77	      <SelectableTable<K8sResourceCommon>
 78	        RowComponent={MockRowComponent}
 79	        columns={getColumns()}
 80	        rows={getRow()}
 81	        setSelectedRows={mockFuncton}
 82	        selectedRows={selectedRows}
 83	        loaded={true}
 84	      />
 85	    );
 86	
 87	    // Header
 88	    expect(screen.getByLabelText('Selectable table')).toBeInTheDocument();
 89	    expect(screen.getByText('name')).toBeInTheDocument();
 90	    expect(screen.getByText('namespace')).toBeInTheDocument();
 91	    expect(screen.getByText('kind')).toBeInTheDocument();
 92	
 93	    // Row1
 94	    expect(screen.getByText('name1')).toBeInTheDocument();
 95	    expect(screen.getByText('namespace1')).toBeInTheDocument();
 96	    expect(screen.getByText('kind1')).toBeInTheDocument();
 97	
 98	    // Row2
 99	    expect(screen.getByText('name2')).toBeInTheDocument();
100	    expect(screen.getByText('namespace2')).toBeInTheDocument();
101	    expect(screen.getByText('kind2')).toBeInTheDocument();
102	
103	    // Row3
104	    expect(screen.getByText('name3')).toBeInTheDocument();
105	    expect(screen.getByText('namespace3')).toBeInTheDocument();
106	    expect(screen.getByText('kind3')).toBeInTheDocument();
107	
108	    // Row action
109	    await user.click(
110	      screen.getAllByRole('button', {
111	        name: 'Kebab toggle',
112	      })[0]
113	    );
114	    expect(screen.getByText('test action')).toBeInTheDocument();
115	  });
116	
117	  test('select one row test', async () => {
118	    const user = userEvent.setup();
119	    let selectedRows: K8sResourceCommon[] = [];
120	    const mockFuncton = jest.fn((selectedRowList: K8sResourceCommon[]) => {
121	      selectedRows = selectedRowList;
122	    });
123	    render(
124	      <SelectableTable<K8sResourceCommon>
125	        RowComponent={MockRowComponent}
126	        columns={getColumns()}
127	        rows={getRow()}
128	        setSelectedRows={mockFuncton}
129	        selectedRows={[]}
130	        loaded={true}
131	      />
132	    );
133	    // Select all rows
134	    const selectRow = screen.getByLabelText('Select row 0');
135	    await user.click(selectRow);
136	    expect(selectedRows.length === 1).toBeTruthy();
137	  });
138	
139	  test('select all row test', async () => {
140	    const user = userEvent.setup();
141	    let selectedRows: K8sResourceCommon[] = [];
142	    const mockFuncton = jest.fn((selectedRowList: K8sResourceCommon[]) => {
143	      selectedRows = selectedRowList;
144	    });
145	    render(
146	      <SelectableTable<K8sResourceCommon>
147	        RowComponent={MockRowComponent}
148	        columns={getColumns()}
149	        rows={getRow()}
150	        setSelectedRows={mockFuncton}
151	        selectedRows={[]}
152	        loaded={true}
153	      />
154	    );
155	    // Select all rows
156	    const selectAll = screen.getByLabelText('Select all rows');
157	    await user.click(selectAll);
158	    expect(selectedRows.length === 2).toBeTruthy();
159	  });
160	
161	  test('No rows test', async () => {
162	    render(
163	      <SelectableTable<K8sResourceCommon>
164	        RowComponent={MockRowComponent}
165	        columns={getColumns()}
166	        rows={[]}
167	        setSelectedRows={jest.fn()}
168	        selectedRows={[]}
169	        loaded={true}
170	      />
171	    );
172	    expect(screen.getByText('Not found')).toBeInTheDocument();
173	  });
174	  test('Load error test', async () => {
175	    render(
176	      <SelectableTable<K8sResourceCommon>
177	        RowComponent={MockRowComponent}
178	        columns={getColumns()}
179	        rows={[]}
180	        setSelectedRows={jest.fn()}
181	        selectedRows={[]}
182	        loaded={true}
183	        loadError={{
184	          response: {
185	            status: 404,
186	          },
187	        }}
188	      />
189	    );
190	    expect(screen.getByText('404: Not Found')).toBeInTheDocument();
191	  });
192	});

